const ShowTrigger = ({
  message,
  onDismiss,
  startVisible = false,
}: {
  message: string;
  onDismiss: () => void;
  startVisible?: boolean;
}) => {
  const [visible, setVisible] = useState(startVisible);
  const dismiss = () => {
    setVisible(false);
    onDismiss();
  };
  return (
    <div className="flex gap-2">
      <button
        type="button"
        onClick={() => setVisible(true)}
        disabled={visible}
        className="rounded-lg bg-primary px-4 py-2 text-primary-foreground disabled:opacity-50"
