import {
  DiceFace,
  DominoTile,
} from '@/games/number-match/NumeralTileBank/NumeralTileBank';

type SlotVariant = 'letter' | 'dice' | 'domino' | 'inline-gap';
type DragPreview = 'none' | 'target-empty' | 'target-swap';

